fixed_code:
use tokio_stream::{wrappers::ReceiverStream, StreamExt};
use tokio::sync::mpsc;

#[tokio::main]
async fn main() {
    let (tx, rx) = mpsc::channel::<i32>(10);
    tokio::spawn(async move {
        for i in 0..5 { tx.send(i).await.unwrap(); }
    });

    let stream = ReceiverStream::new(rx);

    // StreamExt provides async versions of Iterator combinators
    let result: Vec<i32> = stream
        .map(|x| x * 2)
        .filter(|x| std::future::ready(*x > 4))
        .collect()
        .await;  // collect() returns a Future

    println!("{:?}", result);
}

