use tokio_stream::{self, StreamExt};

async fn process_numbers(numbers: impl Iterator<Item = i32>) {
    // Convert Iterator to Stream with iter()
    let mut stream = tokio_stream::iter(numbers);
    while let Some(n) = stream.next().await {
        println!("{}", n * 2);
    }
}

async fn process_and_collect(numbers: impl Iterator<Item = i32>) -> Vec<i32> {
    tokio_stream::iter(numbers)
        .map(|n| n * 2)
        .filter(|n| std::future::ready(*n > 5))
        .collect()
        .await
}

#[tokio::main]
async fn main() {
    process_numbers(0..5).await;
    let result = process_and_collect(0..10).await;
    println!("{:?}", result);
}

