use std::pin::Pin;
use std::task::{Context, Poll};
use futures::Stream;

type BoxFuture<T> = Pin<Box<dyn std::future::Future<Output = T> + Send>>;

struct DbCursor {
    items: Vec<String>,
    pos: usize,
    // For a real async cursor, you'd store a boxed future:
    // pending: Option<BoxFuture<Option<String>>>,
}

impl DbCursor {
    fn new(items: Vec<String>) -> Self {
        DbCursor { items, pos: 0 }
    }
}

impl Stream for DbCursor {
    type Item = String;

    fn poll_next(mut self: Pin<&mut Self>, _cx: &mut Context<'_>) -> Poll<Option<String>> {
        if self.pos < self.items.len() {
            let item = self.items[self.pos].clone();
            self.pos += 1;
            Poll::Ready(Some(item))
        } else {
            Poll::Ready(None)
        }
    }
}

#[tokio::main]
async fn main() {
    use futures::StreamExt;
    let mut cursor = DbCursor::new(vec![
        String::from("row1"),
        String::from("row2"),
    ]);
    while let Some(row) = cursor.next().await {
        println!("{}", row);
    }
}

