use futures::{stream, StreamExt};
use tokio::time::{sleep, Duration};

async fn process(n: i32) -> i32 {
    sleep(Duration::from_millis(100)).await;
    n * 2
}

#[tokio::main]
async fn main() {
    // BUG: calling process(n) eagerly evaluates the async fn,
    // giving a stream of Futures — but the Futures are already
    // created before buffer_unordered sees them.
    // Actually this is correct but let's show a common mistake:

    // Wrong: mapping to the RESULT, not the Future
    let results: Vec<i32> = stream::iter(0..8)
        .map(|n| async move { process(n).await })  // correct form
        .buffer_unordered(4)  // 4 concurrent
        .collect()
        .await;

    println!("{:?}", results);
    // This works, but a common mistake is:
    // .map(|n| process(n).await)  -- ERROR: can't .await in a non-async closure
}

fixed_code:
use futures::{stream, StreamExt};
use tokio::time::{sleep, Duration, Instant};

async fn process(n: i32) -> i32 {
    sleep(Duration::from_millis(50)).await;
    n * 2
}

#[tokio::main]
async fn main() {
    let start = Instant::now();

    // Correct: .map returns a Future (async closure), buffer_unordered runs them concurrently
    let results: Vec<i32> = stream::iter(0..8)
        .map(|n| async move { process(n).await })
        .buffer_unordered(4)  // at most 4 futures running at once
        .collect()
        .await;

    println!("{:?}", results);
    println!("elapsed: {:?}", start.elapsed());  // ~100ms for 8 items with concurrency=4
}

