use std::pin::Pin;
use std::task::{Context, Poll};
use futures::Stream;

// Verbose manual Stream for generating Fibonacci numbers
struct Fibonacci {
    a: u64,
    b: u64,
    max: u64,
}

impl Stream for Fibonacci {
    type Item = u64;
    fn poll_next(mut self: Pin<&mut Self>, _cx: &mut Context<'_>) -> Poll<Option<u64>> {
        if self.a > self.max {
            return Poll::Ready(None);
        }
        let val = self.a;
        let next = self.a + self.b;
        self.a = self.b;
        self.b = next;
        Poll::Ready(Some(val))
    }
}

#[tokio::main]
async fn main() {
    use futures::StreamExt;
    let fib = Fibonacci { a: 0, b: 1, max: 100 };
    let collected: Vec<u64> = fib.collect().await;
    println!("{:?}", collected);
}

