// This compiles, but writing manual Stream impls for every use case is tedious.
// The real problem: for streams with await points inside, you need to store
// futures in the struct, pin them, and implement complex state machines.
// async_stream::stream! provides generator-style syntax instead.

fixed_code:
use async_stream::stream;
use futures::StreamExt;

fn fibonacci(max: u64) -> impl futures::Stream<Item = u64> {
    stream! {
        let (mut a, mut b) = (0u64, 1u64);
        while a <= max {
            yield a;
            let next = a + b;
            a = b;
            b = next;
        }
    }
}

async fn paginated_items(page_count: u32) -> impl futures::Stream<Item = String> {
    stream! {
        for page in 0..page_count {
            // In a real app, you'd await an HTTP or DB call here
            tokio::time::sleep(tokio::time::Duration::from_millis(1)).await;
            for item in 0..3 {
                yield format!("page{}item{}", page, item);
            }
        }
    }
}

#[tokio::main]
async fn main() {
    let fib: Vec<u64> = fibonacci(100).collect().await;
    println!("fibonacci: {:?}", fib);

    let items: Vec<String> = paginated_items(2).await.collect().await;
    println!("items: {:?}", items);
}
